content:
                   .or_insert(ba);
            }
            return 0;
        }

        debug!(
            success_count,
            total = batch.len(),
            "AccessBuffer: flushed access events to Redb"
        );
        success_count
    }
}
pub(crate) fn new(flush_interval_secs: u64, max_pending: usize) -> Self {
        Self {
            pending: DashMap::new(),
            last_flush: AtomicU64::new(epoch_secs()),
            flush_interval_secs,
            max_pending,
            flushing: AtomicBool::new(false),
        }
    }
